import React from "react";
import ReactDOM from "react-dom";
import {Link,Routes, Route, Navigate, BrowserRouter} from 'react-router-dom';
import './Design.css';

function ValidateEmail(inputText)
{
var mailformat = /^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$/;
if(inputText.value.match(mailformat))
{
alert("Valid email address!");
document.form1.text1.focus();
return true;
}
else
{
alert("You have entered an invalid email address!");
document.form1.text1.focus();
return false;
}
}

export default function Login () 
{

    return <>
    <div className="bg">
    <br></br>
    <br></br>
     <div  className="titlebar"> 
        Login
    </div>
    <div  className="form">
        <br></br>
        <br></br>
        <form>
            <input placeholder = "Email" type = "email" id = "email" name='email'></input>
            <br></br>
            <input placeholder = "Password" type = "text" id =  "password" name = "password"></input>
            <br></br>
        </form>
        <div className="center">
        <button  id = "submitButton" type='submit' value="Submit" onclick="ValidateEmail(document.form1.text1)"> Submit </button>
        <br></br>
        </div>
        <br></br>
    </div>
    <p >Not a Member? <Link to = "/" className="link"> Signup</Link></p>
    <br></br>
    </div>
     
    </>
}
